import { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import {
  CreditCard, Plus, Printer, Download, X, Share2, Trash2,
  CheckCircle, AlertTriangle, Clock, Loader2, IndianRupee, Receipt, Wallet
} from 'lucide-react';
